        }

        /// <summary>
        /// 压缩文件并输出
        /// </summary>
        /// <param name="sender"></param>
        /// <param name="e"></param>
        private void btnCompress_Click(object sender, EventArgs e)
        {
            if (txtFile.Text != "")
            {
                if (txtE.Text != "")
                {
                    double temp;
