                        if (sfd.ShowDialog() == DialogResult.OK)
                        {
                            Compress c = new Compress(txtFile.Text, sfd.FileName, temp);
                        }
                    }
                    else
                    {
                        MessageBox.Show("请输入数字！");
                    }
                }
                else
                {
                    MessageBox.Show("请输入数字！");
                }
            }
            else
