                MessageBox.Show("请选择文件！");
            }
        }
    }
}

using System;

namespace 跳马
{
    class Horse
    {
        //记录路径数
        public int num { get; set; }

        int x0, y0, cx, cy;
        int[,] dir = { { 1, 2 }, { 2, 1 }, { 2, -1 }, { 1, -2 }, { -1, -2 }, { -2, -1 }, { -2, 1 }, { -1, 2 } };           //方位矩阵
        int[,] path = new int[100, 2];         //记录路径
        int[,] result = new int[20, 20];          //记录结果

        // 通过构造函数获得初始位置，棋盘大小等信息，
        // 并运行计算
        public Horse(int x0, int y0, int cx, int cy)
        {
            path[0, 0] = this.x0 = x0;
            path[0, 1] = this.y0 = y0;
            this.cx = cx;
            this.cy = cy;
            num = 0;
            Move(x0, y0, 0, 1);
        }

        //计算路径
        void Move(int x, int y, int m, int step)
        {
            int x1, y1;//记录棋子当前位置
            for (int i = m; i < 8; i++)
            {
                int flag = 0;//用作标记

                //朝某一方向前进一步
                x1 = x + dir[i, 0];
                y1 = y + dir[i, 1];

                //如果超出棋盘，回退
                if (x1 < 1 || x1 > cx || y1 < 1 || y1 > cy)
                {
                    x1 -= dir[i, 0];
                    y1 -= dir[i, 1];
                    continue;
                }

                //判断是否走过，走过回退
                for (int j = 1; j <= step; j++)
                {
                    if (x1 == path[j, 0] && y1 == path[j, 1])
                    {
                        flag = 1;
                        break;
                    }
                }
                if (flag == 1)
                {
                    x1 -= dir[i, 0];
                    y1 -= dir[i, 1];
                    continue;
                }

                //符合要求，计入路径
                path[step, 0] = x1;
                path[step, 1] = y1;

                //判断是否回到原点
                if (x1 == x0 && y1 == y0)
                {
                    //如果回到原点，判断是否已经到达过棋盘边缘，初始不算
                    for (int j = 1; j <= step; j++)
                    {
                        if (path[j, 0] == 1 || path[j, 0] == cx || path[j, 1] == 1 || path[j, 1] == cy)
                        {
                            flag = 1;
                        }
                    }

                    //如果到过棋盘边缘，说明路径符合要求，存入路径数组
                    if (flag == 1)
                    {
                        num++;//路径数加一

                        //打印路径
                        Console.Write("方案{0}：", num);
                        for (int j = 0; j <= step; j++)
                        {
                            Console.Write("({0},{1})", path[j, 0], path[j, 1]);
                        }
                        Console.WriteLine();

                        path[step, 0] = 0;
                        path[step, 1] = 0;

                        //回退并继续寻找其他方案
                        step--;
                        i++;

                        Move(path[step,0], path[step,1], i, step + 1);
                    }
                }
                else
                {
                    //未到过边缘，不符合要求，继续寻找路径
                    Move(x1, y1, 1, step + 1);
                }
            }
        }

    }

    class Program
    {
        static void Main(string[] args)
        {
            int x0, y0, cx, cy;

            //获取数据
            Console.Write("请输入棋盘宽度(3≤cx≤20)：");
            cx = int.Parse(Console.ReadLine());
            Console.Write("请输入棋盘长度(3≤cy≤20)：");
            cy = int.Parse(Console.ReadLine());
            Console.Write("请输入起始位置(1≤x0≤cx)：");
            x0 = int.Parse(Console.ReadLine());
            Console.Write("请输入起始位置(1≤y0≤cy)：");
            y0 = int.Parse(Console.ReadLine());

            //进行计算并打印
            Horse horse = new Horse(x0, y0, cx, cy);
            Console.WriteLine("总方案数：{0}", horse.num);

            Console.ReadKey(true);
        }
    }
}

// Program to find the maximum profit job sequence from a given array
// of jobs with deadlines and profits

using System;

namespace 最佳工作序列
{
    class Program
    {
        //任务结构
        public struct Job
        {
            public int id { get; set; }
            public int time { get; set; }
            public int ddl { get; set; }
            public int profit { get; set; }
        }

        public class Work
        {
            //选出价值较大的
            public bool compare(Job a, Job b)
            {
                return (a.profit > b.profit);
            }

            //选出较小值
            public int min(int a, int b)
            {
                if (a <= b)
                    return a;
                else
                    return b;
            }

            //选出较大值
            public int max(int a, int b)
            {
                if (a >= b)
                    return a;
                else
                    return b;
            }

            //冒泡排序算法
            void Sort(Job[] arr)
            {
                for (int i = 0; i < arr.Length - 1; i++)
                {
                    for (int j = 0; j < arr.Length - i - 1; j++)
                    {
                        if (compare(arr[j + 1], arr[j]))
                        {
                            Job tem = arr[j];
                            arr[j] = arr[j + 1];
                            arr[j + 1] = tem;
                        }
                    }
                }
            }

            //计算最佳工作序列
            public void printJobScheduling(Job[] arr, int n)
            {
                //对所有工作进行排序
                Sort(arr);

                //统计最大期限
                int T = 0;
                for (int i = 0; i < n; i++)
                {
                    T = max(T, arr[i].ddl);
                }

                int[] result = new int[n]; //存储队列
                int[] slot = new int[T];  //监控时间间隙

                int t = 0;//工作序列耗时
                int worth = 0;//工作序列总价值

                //初始化时间数组为-1
                for (int i = 0; i < T; i++)
                    slot[i] = -1;

                //计算最佳序列
                for (int i = 0; i < n; i++)
                {
                    //查找期限中是否有时间空位
                    for (int j = arr[i].ddl - 1; j >= 0; j--)
                    {
                        //如果有空位，判断是否有足够费时的时长空隙
                        if (slot[j] == -1)
                        {
                            //标记
                            int flag = 0;

                            //如果空位少于费时，标记为1，并退出
                            for (int k = j; k >= j - arr[i].time + 1; k--)
                            {
                                if (j - arr[i].time + 1 < 0)
                                {
                                    flag = 1;
                                    break;
                                }
                                if (slot[k] != -1) flag = 1;
                            }

                            //当有足够时间，将时间数组命名为任务引导号
                            if (flag == 0)
                            {
                                for (int k = j; k >= j - arr[i].time + 1; k--)
                                    slot[k] = i;
                                break;
                            }
                        }
                    }
                }

                //录入结果
                for (int i = 0; i < n; i++)
                {
                    result[i] = -1;
                }
                for (int i = 0, j = 0; i < n && j < T; j++)
                {
                    if (j == 0)
                    {
                        if (slot[j] != -1)
                        {
                            result[i] = arr[slot[j]].id;
                            t += arr[slot[j]].time;
                            worth += arr[slot[j]].profit;
                            i++;
                            continue;
                        }
                    }
                    if (slot[j] == -1)
                        continue;
                    else if (slot[j] != slot[j - 1])
                    {
                        result[i] = slot[j];
                        t += arr[slot[j]].time;
                        worth += arr[slot[j]].profit;
                        i++;
                        continue;
                    }
                }

                //打印结果
                for (int i = 0; i < n; i++)
                {
                    if (result[i] != -1)
                        Console.Write("{0}", arr[result[i]].id);
                }
                Console.WriteLine();

                //打印时间序列
                Console.Write("时间序列:");
                for(int i=0;i<T;i++)
                {
                    if (slot[i] == -1)
                        Console.Write("0");
                    else
                        Console.Write("{0}", arr[slot[i]].id);
                }
                Console.WriteLine();

                Console.WriteLine("总耗时为:{0}", t);
                Console.WriteLine("总价值为:{0}", worth);
            }
        }

        static void Main(string[] args)
        {
            Work work = new Work();
            Console.Write("请输入任务个数:");
            int n = int.Parse(Console.ReadLine());//记录信息个数

            //输入任务信息
            Job[] arr = new Job[n];
            for (int i = 0; i < n; i++)
            {
                arr[i].id = i + 1;
                Console.Write("请输入任务{0}的费时:", i + 1);
                arr[i].time = int.Parse(Console.ReadLine());
                Console.Write("请输入任务{0}的最后期限:", i + 1);
                arr[i].ddl = int.Parse(Console.ReadLine());
                Console.Write("请输入任务{0}的价值:", i + 1);
                arr[i].profit = int.Parse(Console.ReadLine());
            }

            //打印任务表
            Console.WriteLine();
            Console.WriteLine("ID\t费时\t期限\t价值");
            for (int i = 0; i < n; i++)
            {
                Console.WriteLine("{0}\t{1}\t{2}\t{3}", arr[i].id, arr[i].time, arr[i].ddl, arr[i].profit);
            }
            Console.WriteLine();

            Console.WriteLine("下面即为最佳工作序列");
            work.printJobScheduling(arr, n);
            Console.ReadKey(true);
        }
    }
}
